// Pull both forall ensures into the proof context so the triggers line up
// across the two runs (post1 vs post2). Without this, z3 only sees the
// quantifiers under their original disjoint triggers and never matches them
// up pointwise.
assert(forall|i: int|
    #![trigger post1_self_.page_array@[i]]
    0 <= i < NUM_PAGES && i != index ==>
        post1_self_.page_array@[i] =~= pre_self_.page_array@[i]);
assert(forall|i: int|
    #![trigger post2_self_.page_array@[i]]
    0 <= i < NUM_PAGES && i != index ==>
        post2_self_.page_array@[i] =~= pre_self_.page_array@[i]);

// Pointwise: for each i, post1_self_.page_array@[i] and
// post2_self_.page_array@[i] are forced equal.
assert forall|i: int| 0 <= i < NUM_PAGES implies
    post1_self_.page_array@[i] =~= post2_self_.page_array@[i] by {
    if i == index as int {
        // All field-wise ensures at `index as int` route post1 and post2
        // through pre_self_.page_array@[index as int] (addr, state,
        // is_io_page, rev_pointer, ref_count, mappings, io_mappings), and
        // .owning_container equals `owning_container_op` in both. So the
        // two Page values agree on every field.
    } else {
        // Both equal pre_self_.page_array@[i] via the foralls re-asserted
        // above.
    }
}

// Sequence extensionality lifts pointwise equality of pages to view-equality
// of the underlying Seq<Page>.
assert(post1_self_.page_array@ =~= post2_self_.page_array@);
